INSERT INTO activity_categories (city_slug, slug, visibility, name, description, hero_metric) VALUES
('palermo', 'culture', 'live', '{"en":"Culture","it":"Cultura"}', '{"en":"Museums, theater, guided visits, and family heritage routes.","it":"Musei, teatro, visite guidate e percorsi di patrimonio per famiglie."}', '{"en":"Weekend rituals with clear booking paths.","it":"Riti del weekend con prenotazioni chiare."}'),
