('palermo', 'stem', 'live', '{"en":"Science & STEM","it":"Scienza e STEM"}', '{"en":"Planetarium, coding, robotics, and hands-on discovery.","it":"Planetario, coding, robotica e scoperta hands-on."}', '{"en":"Structured curiosity for 5-14.","it":"Curiosita strutturata per 5-14 anni."}'),
('palermo', 'reading', 'live', '{"en":"Reading & Stories","it":"Lettura e storie"}', '{"en":"Libraries, bookshops, and story-led spaces for younger children.","it":"Biblioteche, librerie e spazi narrativi per i piu piccoli."}', '{"en":"Quiet, trustworthy options for 0-10.","it":"Opzioni tranquille e affidabili per 0-10."}'),
('palermo', 'outdoors', 'live', '{"en":"Outdoor Time","it":"Tempo all aperto"}', '{"en":"Parks and open-air family hubs that work without heavy planning.","it":"Parchi e hub all aperto che funzionano senza pianificazioni pesanti."}', '{"en":"Good-anytime places for family reset.","it":"Luoghi da usare quando serve un reset in famiglia."}'),
