INSERT INTO instructors (city_slug, slug, name, short_bio, specialties, languages) VALUES
('palermo', 'fondazione-teatro-massimo', 'Fondazione Teatro Massimo', '{"en":"The main opera house in Palermo, with guided visits that work well for curious families.","it":"Il principale teatro d opera di Palermo, con visite guidate adatte anche a famiglie curiose."}', '["guided-visit","family-culture"]', '["Italian","English"]'),
('palermo', 'planetario-palermo', 'Planetario Palermo', '{"en":"Weekend dome shows and science storytelling for children and families.","it":"Spettacoli sotto cupola nel weekend e storytelling scientifico per bambini e famiglie."}', '["planetarium-show","science-for-kids"]', '["Italian"]'),
('palermo', 'minimupa', 'MiniMuPa', '{"en":"Interactive museum and creative labs for children, schools, and families.","it":"Museo interattivo e laboratori creativi per bambini, scuole e famiglie."}', '["hands-on-lab","family-culture"]', '["Italian"]'),
('palermo', 'biblioteca-piccolo-principe', 'Biblioteca Il Piccolo Principe', '{"en":"City-run children and teen library with reading, borrowing, and calm indoor time.","it":"Biblioteca comunale per bambini e ragazzi con letture, prestito e tempo indoor tranquillo."}', '["storytime","reading-for-kids"]', '["Italian"]'),
('palermo', 'museo-marionette', 'Museo delle Marionette', '{"en":"Family shows and puppet theater rooted in Palermo’s living tradition.","it":"Spettacoli per famiglie e teatro di figura radicati nella tradizione viva di Palermo."}', '["puppet-theater","family-culture"]', '["Italian"]'),
('palermo', 'palermo-kids-lab', 'Palermo Kids Lab', '{"en":"Small-group coding and digital creativity for older children.","it":"Piccoli gruppi di coding e creativita digitale per bambini piu grandi."}', '["kids-coding","hands-on-lab"]', '["Italian","English"]'),
('palermo', 'circo-pificio-team', 'Circo Pificio team', '{"en":"Local team running circomotricity sessions that work well for younger children with high energy.","it":"Team locale che conduce sessioni di circomotricita adatte ai piu piccoli con energia alta."}', '["circomotricita","active-play"]', '["Italian"]'),
('palermo', 'spazio-terra-team', 'Spazio Terra team', '{"en":"Workshop-led movement team behind kids aerial and body-awareness labs.","it":"Team di laboratorio dietro percorsi aerei e di consapevolezza corporea per bambini."}', '["aerial-kids-lab","movement-lab"]', '["Italian"]'),
('palermo', 'diaria-kids', 'Diaria Kids', '{"en":"Recurring after-school dance and capoeira supply published through Diaria’s Palermo calendar.","it":"Programmazione ricorrente doposcuola di danza e capoeira pubblicata nel calendario palermitano di Diaria."}', '["kids-contemporary-dance","kids-dance-foundations","kids-dance-pedagogy","kids-capoeira","kids-theater"]', '["Italian"]'),
('palermo', 'capoeira-zumbi-team', 'Capoeira Zumbi Palermo', '{"en":"Recurring youth capoeira practice with a stable Palermo base.","it":"Pratica ricorrente di capoeira per ragazzi con una base stabile a Palermo."}', '["kids-capoeira"]', '["Italian"]'),
('palermo', 'le-giuggiole', 'Le Giuggiole', '{"en":"ARCI family circle hosted at EPYC with workshops, play, reading, and cultural activities for children and caregivers.","it":"Circolo ARCI per famiglie ospitato da EPYC con laboratori, gioco, letture e attivita culturali per bambini e accompagnatori."}', '["creative-kids-lab","storytime","family-culture"]', '["Italian"]'),
('palermo', 'booq', 'booq', '{"en":"Neighborhood bibliofficina in the Kalsa with intercultural reading and family-friendly community programming.","it":"Bibliofficina di quartiere alla Kalsa con letture interculturali e programmazione di comunita family-friendly."}', '["storytime","reading-for-kids","community-library"]', '["Italian"]'),
('palermo', 'libreria-dudi', 'Libreria Dudi', '{"en":"Children-focused bookshop and workshop space with reading, science, movement, and music activities from early years to 14.","it":"Libreria per bambini e spazio laboratorio con attivita di lettura, scienza, movimento e musica dalla prima infanzia ai 14 anni."}', '["storytime","creative-kids-lab","reading-for-kids"]', '["Italian"]'),
('palermo', 'giulia-agnello-naturopata', 'Giulia Agnello Naturopata', '{"en":"Natural food educator running family cooking workshops around Palermo with a practical, seasonal approach.","it":"Educatrice al cibo naturale che conduce laboratori di cucina per famiglie a Palermo con un approccio pratico e stagionale."}', '["natural-cooking-lab","hands-on-lab"]', '["Italian"]'),
('palermo', 'radici-museo-natura', 'Radici Museo della Natura', '{"en":"Museum and ecological cultural center with recurring family activities, readings, and hands-on labs.","it":"Museo e centro culturale ecologico con attivita ricorrenti per famiglie, letture e laboratori hands-on."}', '["hands-on-lab","natural-cooking-lab","family-culture"]', '["Italian","English"]'),
('palermo', 'laboratorio-zen-insieme', 'Laboratorio ZEN Insieme', '{"en":"Long-running neighborhood association combining reading, after-school support, culture, and social infrastructure for children.","it":"Associazione di quartiere attiva da anni che intreccia lettura, doposcuola, cultura e infrastruttura sociale per bambini."}', '["storytime","community-library","family-culture"]', '["Italian"]'),
('palermo', 'uci-cinemas-palermo', 'UCI Cinemas Palermo', '{"en":"Multiplex at Forum Palermo with weekly Kids Club screenings and autism-friendly family slots.","it":"Multisala a Forum Palermo con proiezioni settimanali Kids Club e slot family anche autism friendly."}', '["family-screening","family-cinema","autism-friendly"]', '["Italian"]'),
('palermo', 'cinema-city-palermo', 'Cinema City Palermo', '{"en":"Citywide open-air cinema project with seasonal screenings in public spaces, including family-accessible titles.","it":"Rassegna di cinema nelle piazze con proiezioni stagionali negli spazi pubblici, incluse serate accessibili alle famiglie."}', '["family-screening","open-air-cinema","civic-culture"]', '["Italian"]')
