('palermo', 'capo', 'biblioteca-piccolo-principe-place', 'Biblioteca Il Piccolo Principe', '{"en":"Quiet reading and story-led time for younger families.","it":"Tempo tranquillo di lettura e storie per le famiglie piu giovani."}', '{"en":"A strong fallback when you need something gentle, free, and central during the week.","it":"Un ottimo fallback quando serve qualcosa di gentile, gratuito e centrale durante la settimana."}', 'Cortile Scalilla 37, Palermo', 38.1189, 13.3513, '["Free access","0-6 area","Borrowing"]', '["Italian"]', '["storytime"]', '["reading"]', '["biblioteca-contact"]', '{"en":"Core opening hours and family services checked from municipal library information.","it":"Orari base e servizi per famiglie controllati dalle informazioni comunali."}', 'https://www.comune.palermo.it/', '2026-03-29T11:00:00+02:00'),
('palermo', 'kalsa', 'museo-marionette-palermo', 'Museo delle Marionette', '{"en":"Weekend theater with one of Palermo’s strongest family identities.","it":"Teatro del weekend con una delle identita family piu forti di Palermo."}', '{"en":"Useful when the family wants one cultural plan that still feels playful and visually rich.","it":"Utile quando la famiglia vuole un piano culturale che resti giocoso e visivamente ricco."}', 'Piazzetta Antonio Pasqualino 5, Palermo', 38.1178, 13.3699, '["Indoor","Family theater","Weekend rhythm"]', '["Italian"]', '["puppet-theater"]', '["culture"]', '["museo-marionette-contact"]', '{"en":"Recurring family shows tracked from the museum’s public program.","it":"Spettacoli ricorrenti per famiglie tracciati dal programma pubblico del museo."}', 'https://www.museomarionettepalermo.it/', '2026-03-29T11:00:00+02:00'),
('palermo', 'politeama', 'villa-filippina-palermo', 'Parco Villa Filippina', '{"en":"A dependable outdoor reset without heavy logistics.","it":"Un reset all aperto affidabile senza logistica pesante."}', '{"en":"Use it as a good-anytime outdoor anchor when the family needs movement and space more than a ticketed program.","it":"Da usare come ancora outdoor good-anytime quando la famiglia ha bisogno di spazio e movimento piu che di un programma ticketed."}', 'Piazza San Francesco di Paola 18, Palermo', 38.1248, 13.3513, '["Outdoor","Play area","Open access"]', '["Italian"]', '["open-park-day"]', '["outdoors"]', '["villa-filippina-info"]', '{"en":"Access and contact details checked from public city-facing sources.","it":"Accesso e contatti controllati da fonti pubbliche cittadine."}', 'https://www.parcovillafilippina.it/', '2026-03-29T11:00:00+02:00'),
('palermo', 'politeama', 'palermo-kids-lab-place', 'Palermo Kids Lab', '{"en":"Small-group coding for older children after school and on Saturdays.","it":"Coding in piccoli gruppi per i piu grandi dopo scuola e il sabato."}', '{"en":"A practical STEM option when you want continuity instead of a one-off workshop.","it":"Un opzione STEM pratica quando serve continuita invece di un workshop singolo."}', 'Via Dante 52, Palermo', 38.1274, 13.3506, '["Small groups","Indoor","Beginner friendly"]', '["Italian","English"]', '["kids-coding"]', '["stem"]', '["kids-lab-booking"]', '{"en":"Published beginner coding slots tracked from the organizer’s public page.","it":"Slot di coding beginner tracciati dalla pagina pubblica dell organizzatore."}', 'https://www.palermokidslab.it/', '2026-03-29T11:00:00+02:00'),
('palermo', 'politeama', 'circo-pificio-palermo', 'Circo Pificio', '{"en":"Circomotricity and active play for children with a real weekly rhythm.","it":"Circomotricita e gioco motorio per bambini con un vero ritmo settimanale."}', '{"en":"A focused movement pick for families who want coordination, balance, and fun without the chaos of a generic playroom.","it":"Una scelta motoria centrata per famiglie che cercano coordinazione, equilibrio e divertimento senza il caos di una ludoteca generica."}', 'Via Serradifalco 130, Palermo', 38.1239, 13.3394, '["Small groups","Movement lab","Kids-focused programming"]', '["Italian"]', '["circomotricita"]', '["movement"]', '["circopificio-website"]', '{"en":"Current public program checked from the official circomotricity page.","it":"Programma pubblico corrente controllato dalla pagina ufficiale di circomotricita."}', 'https://www.circopificio.it/circomotricita/', '2026-03-12T12:00:00+01:00'),
